import{_ as e,o as a,c as d,ak as s}from"./chunks/framework.DwHlt8HN.js";const b=JSON.parse('{"title":"分布式锁","description":"","frontmatter":{},"headers":[],"relativePath":"distributed/lock/index.md","filePath":"distributed/lock/index.md","lastUpdated":1774319300000}'),i={name:"distributed/lock/index.md"};function r(n,t,l,o,h,p){return a(),d("div",null,[...t[0]||(t[0]=[s(`<h1 id="分布式锁" tabindex="-1">分布式锁 <a class="header-anchor" href="#分布式锁" aria-label="Permalink to “分布式锁”">​</a></h1><p>你有没有想过这个问题：</p><p>单机环境下，<code>synchronized</code> 和 <code>ReentrantLock</code> 足够。</p><p>但如果是集群部署呢？多台机器同时抢一把锁，怎么保证互斥？</p><p><strong>单机锁解决的是进程内的问题，分布式锁解决的是跨机器的问题。</strong></p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>分布式锁是分布式系统中最重要的基础设施之一。</p><table tabindex="0"><thead><tr><th>章节</th><th>篇数</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="/distributed/lock/requirements">分布式锁基础</a></td><td>1 篇</td><td>五大要求：互斥、可重入、不死锁、公平性、高性能</td></tr><tr><td><a href="/distributed/lock/redis-lock">Redis 分布式锁</a></td><td>8 篇</td><td>SETNX、Redisson、看门狗、公平锁、读写锁、联锁</td></tr><tr><td><a href="/distributed/lock/mysql-lock">其他实现方案</a></td><td>3 篇</td><td>MySQL 唯一索引、ZooKeeper 临时顺序节点、对比选型</td></tr></tbody></table><h2 id="五大要求" tabindex="-1">五大要求 <a class="header-anchor" href="#五大要求" aria-label="Permalink to “五大要求”">​</a></h2><p>分布式锁必须满足以下五个条件：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>1. 互斥性：在任意时刻，只有一个客户端持有锁</span></span>
<span class="line"><span>2. 不会死锁：即使客户端崩溃，锁也能被释放（TTL / Lease）</span></span>
<span class="line"><span>3. 可重入：同一个客户端可以多次获取同一把锁</span></span>
<span class="line"><span>4. 公平性（可选）：锁按请求顺序分配（FIFO）</span></span>
<span class="line"><span>5. 高性能：获取 / 释放锁的操作必须快</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="实现方案对比" tabindex="-1">实现方案对比 <a class="header-anchor" href="#实现方案对比" aria-label="Permalink to “实现方案对比”">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>性能</th><th>可靠性</th><th>实现复杂度</th><th>适用场景</th></tr></thead><tbody><tr><td>Redis SETNX</td><td>最高</td><td>中</td><td>中</td><td>高性能场景</td></tr><tr><td>Redisson</td><td>高</td><td>高</td><td>低</td><td>推荐使用</td></tr><tr><td>ZooKeeper</td><td>中</td><td>高</td><td>高</td><td>高可靠性场景</td></tr><tr><td>MySQL</td><td>低</td><td>高</td><td>低</td><td>备选方案</td></tr><tr><td>etcd</td><td>中</td><td>高</td><td>中</td><td>K8s 生态</td></tr></tbody></table><h2 id="面试高频问题" tabindex="-1">面试高频问题 <a class="header-anchor" href="#面试高频问题" aria-label="Permalink to “面试高频问题”">​</a></h2><h3 id="q1-redis-分布式锁如何实现可重入" tabindex="-1">Q1：Redis 分布式锁如何实现可重入？ <a class="header-anchor" href="#q1-redis-分布式锁如何实现可重入" aria-label="Permalink to “Q1：Redis 分布式锁如何实现可重入？”">​</a></h3><blockquote><p>「Redis Hash 结构存储锁信息：key=锁名，field=持有者 ID，value=重入计数。 获取锁时，如果是自己持有则计数+1 并续期；否则尝试获取锁。 释放锁时，计数归零才真正删除锁。」</p></blockquote><h3 id="q2-redisson-的看门狗机制是什么" tabindex="-1">Q2：Redisson 的看门狗机制是什么？ <a class="header-anchor" href="#q2-redisson-的看门狗机制是什么" aria-label="Permalink to “Q2：Redisson 的看门狗机制是什么？”">​</a></h3><blockquote><p>「看门狗解决的是「锁 TTL 到了但业务还没执行完」的问题。 Redisson 默认每 10 秒自动续期一次（internalLockLeaseTime / 3）。 只要持有锁的业务还在运行，看门狗就会一直续期。 业务执行完毕后释放锁，看门狗自动停止。」</p></blockquote><h3 id="q3-redis-分布式锁超时了怎么办" tabindex="-1">Q3：Redis 分布式锁超时了怎么办？ <a class="header-anchor" href="#q3-redis-分布式锁超时了怎么办" aria-label="Permalink to “Q3：Redis 分布式锁超时了怎么办？”">​</a></h3><blockquote><p>「锁超时的本质是：业务执行时间 &gt; 锁 TTL。 解决方案有三个：</p><ol><li>合理评估 TTL + 看门狗续期</li><li>任务设计为可中断的，分段执行</li><li>锁值中携带预期完成时间，检查任务是否超时再继续」</li></ol></blockquote><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to “延伸阅读”">​</a></h2><p>分布式锁的选择建议：</p><ul><li><strong>Redis</strong>：首选方案，推荐使用 Redisson，性能最高</li><li><strong>ZooKeeper</strong>：金融、配置等高可靠性场景</li><li><strong>MySQL</strong>：作为备选或过渡方案</li></ul><p>记住：<strong>没有最好的方案，只有最合适的方案。</strong></p>`,24)])])}const k=e(i,[["render",r]]);export{b as __pageData,k as default};
